// Notion's /v1/search returns a single item with a results[] array.
// Unwrap each page into its own item, then drop anything older than the
// polling window (2 min + a little slack).  Notion doesn't support server-
// side last_edited_time filters on /search, so this client-side filter is
// required to avoid re-ingesting the same pages every poll.

const WINDOW_MS = 2.5 * 60 * 1000;
const now = Date.now();

const results = [];
for (const item of $input.all()) {
  const pages = item.json.results || [];
  for (const page of pages) {
    const editedAt = new Date(page.last_edited_time || 0).getTime();
    if (!editedAt || (now - editedAt) > WINDOW_MS) continue;
    results.push({ json: page });
  }
}

return results;

// Classify what changed on each Notion page and produce a normalized
// event for the Laya engine.  Actor info is limited to the user ID
// returned by the Notion page object — resolving to name/email would
// require a secondary /v1/users/{id} call per page, which we skip at
// poll time to keep this workflow cheap.  team.json mapping handles
// the enrichment downstream.

const results = [];

for (const item of $input.all()) {
  const page = item.json;

  // --- Title: find the title property on the page ---
  let title = '(Untitled)';
  const props = page.properties || {};
  for (const prop of Object.values(props)) {
    if (prop && prop.type === 'title' && Array.isArray(prop.title)) {
      const rendered = prop.title.map(t => t.plain_text || '').join('').trim();
      if (rendered) { title = rendered; break; }
    }
  }

  // --- Classify change type ---
  const created = page.created_time;
  const updated = page.last_edited_time;
  const isNew = created === updated;
  const archived = page.archived === true;

  let rawEventType = 'page_updated';
  let body = '';

  if (archived) {
    rawEventType = 'page_archived';
    body = `Page archived: ${title}`;
  } else if (isNew) {
    rawEventType = 'page_created';
    body = `New page created: ${title}`;
  } else {
    rawEventType = 'page_updated';
    body = `Page updated: ${title}`;
  }

  // --- Parent context ---
  const parent = page.parent || {};
  const parentType = parent.type || 'workspace';
  const parentId = parent.database_id || parent.page_id || parent.block_id || null;

  // --- Participants ---
  const creator = page.created_by || {};
  const editor = page.last_edited_by || {};
  const participants = [];
  if (creator.id) {
    participants.push({
      role: 'creator',
      name: '',
      email: '',
      handle: creator.id
    });
  }
  if (editor.id && editor.id !== creator.id) {
    participants.push({
      role: 'last_editor',
      name: '',
      email: '',
      handle: editor.id
    });
  }

  const actorHandle = editor.id || creator.id || '';

  results.push({
    json: {
      event_id: 'evt_notion_' + (page.id || '').replace(/-/g, '') + '_' + new Date(updated || Date.now()).getTime(),
      timestamp: updated || new Date().toISOString(),
      source: {
        platform: 'notion',
        connection_id: $workflow.id,
        raw_event_type: rawEventType
      },
      actor: {
        name: '',
        email: '',
        platform_handle: actorHandle
      },
      subject: {
        type: 'page',
        id: page.id || '',
        title: title,
        url: page.url || null
      },
      content: {
        body: body,
        attachments: [],
        metadata: {
          notion_page_id: page.id,
          notion_parent_id: parentId,
          notion_parent_type: parentType,
          notion_archived: archived,
          notion_created_time: created,
          notion_last_edited_time: updated,
          notion_cover_url: page.cover?.external?.url || page.cover?.file?.url || null,
          notion_icon: page.icon?.emoji || page.icon?.external?.url || null,
          participants: participants
        }
      }
    }
  });
}

return results;
